### Step 3: Define a Move
A move consists of a start position and an end position, including capture information.

```python
class Move:
    def __init__(self, start, end, capture=None):
        self.start = start
        self.end = end
        self.capture = capture

    @property
    def is_capture(self):
        return bool(self.capture)

    def apply(self, board):
        piece = board[self.start[0]][self.start[1]]
        board[self.start[0]][self.start[1]] = None
        board[self.end[0]][self.end[1]] = piece
        if self.is_capture:
            captured_row = (self.start[0] + self.end[0]) // 2
            captured_col = (self.start[1] + self.end[1]) // 2
            board[captured_row][captured_col] = None

    def undo(self, board):
        piece = board[self.end[0]][self.end[1]]
        board[self.end[0]][self.end[1]] = None
        if piece.is_king:
            piece.is_king = False
        board[self.start[0]][self.start[1]] = piece
        if self.is_capture:
            captured_row = (self.start[0] + self.end[0]) // 2
            captured_col = (self.start[1] + self.end[1]) // 2
            board[captured_row][captured_col] = Piece(piece.color)
