```python
class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = "black"
        self.history = []

    def print_board(self):
        self.board.print_board()

    def switch_turn(self):
        if self.current_player == "black":
            self.current_player = "white"
        else:
            self.current_player = "black"

    def get_possible_moves(self, start_row, start_col):
        piece = self.board.board[start_row][start_col]
        if not piece or piece.color != self.current_player:
            return []

        moves = []
        row, col = start_row, start_col
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]

        for dr, dc in directions:
            nrow, ncol = row + dr, col + dc
            if self.board.is_valid_position(nrow, ncol) and not self.board.is_occupied(nrow, ncol):
                moves.append(Move((row, col), (nrow, ncol)))
                if piece.is_king:
                    continue

            # Check for captures
            ndr, ndc = dr * 2, dc * 2
            nnrow, nncol = row + ndr, col + ndc
            if self.board.is_valid_position(nnrow, nncol) and not self.board.is_occupied(nnrow, nncol):
                capture_piece = self.board.board[nrow][ncol]
                if capture_piece and capture_piece.color != piece.color:
                    moves.append(Move((row, col), (nnrow, nncol), (nrow, ncol)))

        return moves

    def is_valid_move(self, move):
        if not move.is_capture:
            start_row, start_col = move.start
            end_row, end_col = move.end
            piece = self.board.board[start_row][start_col]
            return self.get_possible_moves(start_row, start_col) and (end_row, end_col) in [move.end for move in self.get_possible_moves(start_row, start_col)]
        else:
            return move in [move for moves in [self.get_possible_moves(row, col) for row in range(8) for col in range(8)] for move in moves if move.is_capture]

    def make_move(self, move):
        if not self.is_valid_move(move):
            raise ValueError("Invalid move")

        move.apply(self.board)
        self.history.append(move)

    def undo_move(self):
        if self.history:
            last_move = self.history.pop()
            last_move.undo(self.board)
            self.switch_turn()

    def check_win_draw(self):
        black_moves = [move for row in range(8) for col in range(8) if self.get_possible_moves(row, col)]
        white_moves = [move for row in range(8) for col in range(8) if self.get_possible_moves(row, col)]

        if not black_moves and self.current_player == "black":
            print("White wins!")
            return True
        elif not white_moves and self.current_player == "white":
            print("Black wins!")
            return True

        if len(self.history) >= 64:  # Assuming the maximum number of moves is 64
            print("Draw by stalemate!")
            return True

        return False

    def play(self):
        while True:
            self.print_board()
            move_input = input(f"Player {self.current_player}, enter your move (from-to): ")
            start, end = move_input.split("-")
            start_row, start_col = int(start[0]), int(start[1])
            end_row, end_col = int(end[0]), int(end[1])

            move = Move((start_row, start_col), (end_row, end_col))
            try:
                self.make_move(move)
                if self.check_win_draw():
                    break
                self.switch_turn()
            except ValueError as e:
                print(e)
