class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        colors = ['red', 'black']
        for row, color in enumerate(colors):
            for col in range((row % 2) + (color == 'red')):
                if (col + row) % 2 != 0:
                    self.board[row][col] = Piece(color)

    def display(self):
        # Display the board
        for row in self.board:
            print(" ".join(f"{piece.symbol() if piece else '.'}" for piece in row))

    def move_piece(self, start_pos, end_pos):
        # Move a piece from start_pos to end_pos
        if 0 <= start_pos[0] < 8 and 0 <= start_pos[1] < 8 and 0 <= end_pos[0] < 8 and 0 <= end_pos[1] < 8:
            piece = self.board[start_pos[0]][start_pos[1]]
            if piece and (end_pos[0], end_pos[1]) in piece.get_moves(self):
                self.board[end_pos[0]][end_pos[1]] = piece
                self.board[start_pos[0]][start_pos[1]] = None
                return True
        return False

    def get_valid_moves(self, player_color):
        # Get all valid moves for a given player
        valid_moves = []
        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece and piece.color == player_color:
                    valid_moves.extend(piece.get_moves(self))
        return valid_moves

    def is_game_over(self):
        # Check if the game is over
        red_pieces = [piece for row in self.board for piece in row if piece and piece.color == 'red']
        black_pieces = [piece for row in self.board for piece in row if piece and piece.color == 'black']
        return len(red_pieces) == 0 or len(black_pieces) == 0
